import "core-js/modules/web.dom-collections.for-each.js";
import "core-js/modules/es.array.push.js";
/**
 * 将 1 列匹配赛，格式化为 2 列
 * @param scheList 赛程列表
 * @returns 新的赛程列表
 */
export function formatMatchAllScheList(scheList) {
  var anotherLine = [];
  var firstLine = [];
  if (!scheList.length) return [];
  scheList[0].forEach(function (item, index) {
    if (index % 2 === 1) {
      anotherLine.push(item);
    } else {
      firstLine.push(item);
    }
  });
  if (firstLine.length !== anotherLine.length) {
    anotherLine.push({
      battleList: [{}],
      upScheGroup: {},
      hidden: true
    });
  }
  var res = [firstLine, anotherLine];
  return res;
}